        for(auto i : asteroids){
            if(mystack.isEmpty()){
                mystack.push(i);
            }
            else if(i > 0){
                mystack.push(i);
            }
            else{
                bool test = true;
                while(!mystack.isEmpty() && test){
                    if(abs(i) > mystack.top()){
                        if(mystack.top() < 0){
                            mystack.push(i);
                            test = false;
                        }else{
                            mystack.pop();
                        }
